// Some portions generated by Co-Pilot
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import DocSidebar, { getSectionForPath } from "../index";
import { usePathname } from "@/i18n/navigation";

vi.mocked(usePathname);

describe("DocSidebar", () => {
  it("renders installation section when on installation path", () => {
    vi.mocked(usePathname).mockReturnValue("/installation");
    render(<DocSidebar />);

    expect(screen.getByText("Installation")).toBeInTheDocument();
    expect(screen.getByText("Overview")).toBeInTheDocument();
    expect(screen.getByText("Windows MSI Installer")).toBeInTheDocument();
    expect(screen.getByText("macOS PKG Installer")).toBeInTheDocument();
    expect(screen.getByText("Linux (RPM/DEB/APK)")).toBeInTheDocument();
    expect(screen.getByText("Archive Files")).toBeInTheDocument();
  });

  it("renders docs section when on docs path", () => {
    vi.mocked(usePathname).mockReturnValue("/docs/faq");
    render(<DocSidebar />);

    expect(screen.getByText("Documentation")).toBeInTheDocument();
    expect(screen.getByText("FAQ")).toBeInTheDocument();
    expect(screen.getByText("Migration Guide")).toBeInTheDocument();
  });

  it("renders temurin section when on temurin path", () => {
    vi.mocked(usePathname).mockReturnValue("/temurin/buttons");
    render(<DocSidebar />);

    expect(screen.getByText("Temurin")).toBeInTheDocument();
    expect(screen.getByText("Commercial Support")).toBeInTheDocument();
  });

  it("renders nothing when path does not match any section", () => {
    vi.mocked(usePathname).mockReturnValue("/about");
    const { container } = render(<DocSidebar />);

    expect(container.innerHTML).toBe("");
  });

  it("highlights active link", () => {
    vi.mocked(usePathname).mockReturnValue("/installation/linux");
    const { container } = render(<DocSidebar />);

    const links = container.querySelectorAll("a");
    const activeLink = Array.from(links).find(
      (a) => a.textContent === "Linux (RPM/DEB/APK)",
    );
    expect(activeLink).toHaveClass("text-pink");
  });

  it("does not highlight inactive links", () => {
    vi.mocked(usePathname).mockReturnValue("/installation/linux");
    const { container } = render(<DocSidebar />);

    const links = container.querySelectorAll("a");
    const inactiveLink = Array.from(links).find(
      (a) => a.textContent === "Overview",
    );
    expect(inactiveLink).not.toHaveClass("text-pink");
  });

  it("has accessible navigation landmark", () => {
    vi.mocked(usePathname).mockReturnValue("/installation");
    const { container } = render(<DocSidebar />);

    const nav = container.querySelector("nav");
    expect(nav).toHaveAttribute("aria-label", "Documentation navigation");
  });
});

describe("getSectionForPath", () => {
  it("returns installation section for installation paths", () => {
    const section = getSectionForPath("/installation");
    expect(section?.title).toBe("Installation");
  });

  it("returns docs section for docs paths", () => {
    const section = getSectionForPath("/docs/faq");
    expect(section?.title).toBe("Documentation");
  });

  it("returns temurin section for temurin paths", () => {
    const section = getSectionForPath("/temurin/buttons");
    expect(section?.title).toBe("Temurin");
  });

  it("returns null for unknown paths", () => {
    expect(getSectionForPath("/about")).toBeNull();
    expect(getSectionForPath("/")).toBeNull();
  });
});
